def caesar_decrypt(ciphertext, key):
    result = []
    for ch in ciphertext:
        if ch.isalpha():
            base = ord('A') if ch.isupper() else ord('a')
            result.append(chr((ord(ch) - base - key) % 26 + base))
        else:
            result.append(ch)
    return ''.join(result)

# 1) 키를 알 때 복호화
c1 = "PHHW DW VFKRRO DW ILYH SP"
print("키=3 복호화:", caesar_decrypt(c1, 3))

# 2) 키를 모를 때 무차별 대입(brute force)
c2 = "FIEYXC FIKMRW XLI QSQIRX CSY HIGMHI XS FI CSYVWIPJ. FI CSYVWIPJ, RS SRI GER WEC CSY'VI HSMRK MX AVSRK."
for key in range(1, 26):
    guess = caesar_decrypt(c2, key)
    if "THE" in guess or "YOU" in guess:  # 뜻이 통하는 후보만 출력
        print(f"키={key}: {guess}")

def transpose_encrypt(plaintext, key):
    key = [int(k) for k in str(key)]
    return ''.join(plaintext[k - 1] for k in key)

def transpose_decrypt(ciphertext, key):
    key = [int(k) for k in str(key)]
    n = len(key)
    result = [''] * n
    for i, k in enumerate(key):
        result[k - 1] = ciphertext[i]
    return ''.join(result)

plaintext = "COMPUTER"
key = "35164827"
ciphertext = transpose_encrypt(plaintext, key)
print("평문:", plaintext)
print("암호문:", ciphertext)
print("다시 복호화:", transpose_decrypt(ciphertext, key))
